parameters.functionCode:
const books = $json.items ?? [];
const allowedLicenses = new Set(['CC-BY-4.0', 'CC-BY-SA-4.0']);
return books
  .filter((b) => b.license_name && allowedLicenses.has(b.license_name.replace(/\s/g, '-')))
  .map((b) => ({
    json: {
      id: `openstax-${b.slug}`,
      title: b.title,
      description: `OpenStax open textbook: ${b.title}`,
      sourceId: 'openstax',
      url: `https://openstax.org/details/books/${b.slug}`,
      subjects: [],
      media: ['textbook'],
      level: 'ug',
      institution: 'OpenStax, Rice University',
      license: b.license_name.replace(/\s/g, '-'),
      licenseUrl: b.license_url ?? 'https://creativecommons.org/licenses/by/4.0/',
      gateTopics: [],
      tags: ['textbook']
    }
  }));
